#include <iostream>

template <typename T>
T printValue(T value) { 
    std::cout << "Value: " << value << std::endl;
}

int main() {
    int int_val = printValue(10);
    char char_val = printValue('A');

    std::cout << "Returned int_val: " << int_val << std::endl;
    std::cout << "Returned char_val: " << char_val << std::endl;

    return 0;
}
